  1	import React, { Dispatch, FC, SetStateAction, useEffect, useRef, useState } from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import { isEmpty } from '@kubevirt-utils/utils/utils';
  5	import {
  6	  Button,
  7	  ButtonVariant,
  8	  KeyTypes,
  9	  MenuToggle,
 10	  MenuToggleElement,
 11	  Select,
 12	  SelectList,
 13	  SelectOption,
 14	  SelectOptionProps,
 15	  TextInputGroup,
 16	  TextInputGroupMain,
 17	  TextInputGroupUtilities,
 18	} from '@patternfly/react-core';
 19	import { FolderIcon, SearchIcon } from '@patternfly/react-icons';
 20	import TimesIcon from '@patternfly/react-icons/dist/esm/icons/times-icon';
 21	
 22	import { CREATE_NEW, NOT_FOUND } from './utils/constants';
 23	import { createItemId } from './utils/utils';
 24	
 25	type SelectTypeaheadProps = {
 26	  canCreate?: boolean;
 27	  dataTestId?: string;
 28	  getCreateOption?: (inputValue: string, canCreate?: boolean) => SelectOptionProps;
 29	  initialOptions: SelectOptionProps[];
 30	  isFullWidth?: boolean;
 31	  placeholder?: string;
 32	  selected: string;
 33	  setInitialOptions?: Dispatch<SetStateAction<SelectOptionProps[]>>;
 34	  setSelected: (newFolder: string) => void;
 35	};
 36	
 37	const SelectTypeahead: FC<SelectTypeaheadProps> = ({
 38	  canCreate = false,
 39	  dataTestId,
 40	  getCreateOption,
 41	  initialOptions,
 42	  isFullWidth = false,
 43	  placeholder,
 44	  selected,
 45	  setInitialOptions,
 46	  setSelected,
 47	}) => {
 48	  const { t } = useKubevirtTranslation();
 49	  const [isOpen, setIsOpen] = useState(false);
 50	  const [inputValue, setInputValue] = useState<string>(selected);
 51	  const [filterValue, setFilterValue] = useState<string>('');
 52	  const [selectOptions, setSelectOptions] = useState<SelectOptionProps[]>();
 53	  const [focusedItemIndex, setFocusedItemIndex] = useState<null | number>(null);
 54	  const [activeItemId, setActiveItemId] = useState<null | string>(null);
 55	  const textInputRef = useRef<HTMLInputElement>();
 56	
 57	  useEffect(() => {
 58	    const newSelectOptions: SelectOptionProps[] = filterValue
 59	      ? (initialOptions || [])?.filter((menuItem) =>
 60	          String(menuItem.children).toLowerCase().includes(filterValue.toLowerCase()),
 61	        )
 62	      : initialOptions || [];
 63	
 64	    if (canCreate) {
 65	      const createOption = getCreateOption?.(filterValue, canCreate);
 66	      if (createOption && !newSelectOptions.some((option) => option.value === CREATE_NEW)) {
 67	        newSelectOptions.push(createOption);
 68	      }
 69	    }
 70	
 71	    if (!canCreate && newSelectOptions.length === 0 && filterValue) {
 72	      newSelectOptions.push({ children: t('Not found'), isDisabled: true, value: NOT_FOUND });
 73	    }
 74	
 75	    setSelectOptions(newSelectOptions);
 76	  }, [canCreate, filterValue, getCreateOption, initialOptions, t]);
 77	
 78	  const setActiveAndFocusedItem = (itemIndex: number) => {
 79	    setFocusedItemIndex(itemIndex);
 80	    const focusedItem = selectOptions[itemIndex];
 81	    setActiveItemId(createItemId(focusedItem.value));
 82	  };
 83	
 84	  const resetActiveAndFocusedItem = () => {
 85	    setFocusedItemIndex(null);
 86	    setActiveItemId(null);
 87	  };
 88	
 89	  const closeMenu = () => {
 90	    setIsOpen(false);
 91	    resetActiveAndFocusedItem();
 92	  };
 93	
 94	  const selectOption = (value: number | string, content: number | string) => {
 95	    setInputValue(String(content));
 96	    setFilterValue('');
 97	    setSelected(String(value));
 98	
 99	    closeMenu();
100	  };
101	
102	  const onSelect = (
103	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
104	    value: number | string | undefined,
105	  ) => {
106	    if (!value) return;
107	
108	    if (value === CREATE_NEW) {
109	      if (!initialOptions?.some((item) => item.children === filterValue)) {
110	        setInitialOptions?.((prevFolders) => [
111	          ...(prevFolders || []),
112	          { children: filterValue, icon: <FolderIcon />, value: filterValue },
113	        ]);
114	      }
115	      setSelected(filterValue);
116	      setFilterValue('');
117	      closeMenu();
118	      return;
119	    }
120	
121	    const optionChildren = selectOptions.find((option) => option.value === value)?.children;
122	
123	    if (typeof optionChildren === 'object') return selectOption(value, value);
124	
125	    selectOption(value, optionChildren as string);
126	  };
127	
128	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
129	    setInputValue(value);
130	    setFilterValue(value);
131	
132	    if (!isEmpty(value) && !isOpen) setIsOpen(true);
133	
134	    resetActiveAndFocusedItem();
135	
136	    if (value !== selected) {
137	      setSelected('');
138	    }
139	  };
140	
141	  const handleMenuArrowKeys = (key: string) => {
142	    let indexToFocus = 0;
143	
144	    if (!isOpen) {
145	      setIsOpen(true);
146	    }
147	
148	    if (selectOptions.every((option) => option.isDisabled)) {
149	      return;
150	    }
151	
152	    if (key === KeyTypes.ArrowUp) {
153	      // When no index is set or at the first index, focus to the last, otherwise decrement focus index
154	      if (focusedItemIndex === null || focusedItemIndex === 0) {
155	        indexToFocus = selectOptions.length - 1;
156	      } else {
157	        indexToFocus = focusedItemIndex - 1;
158	      }
159	
160	      // Skip disabled options
161	      while (selectOptions[indexToFocus].isDisabled) {
162	        indexToFocus--;
163	        if (indexToFocus === -1) {
164	          indexToFocus = selectOptions.length - 1;
165	        }
166	      }
167	    }
168	
169	    if (key === KeyTypes.ArrowDown) {
170	      // When no index is set or at the last index, focus to the first, otherwise increment focus index
171	      if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
172	        indexToFocus = 0;
173	      } else {
174	        indexToFocus = focusedItemIndex + 1;
175	      }
176	
177	      // Skip disabled options
178	      while (selectOptions[indexToFocus].isDisabled) {
179	        indexToFocus++;
180	        if (indexToFocus === selectOptions.length) {
181	          indexToFocus = 0;
182	        }
183	      }
184	    }
185	
186	    setActiveAndFocusedItem(indexToFocus);
187	  };
188	
189	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
190	    const focusedItem = focusedItemIndex !== null ? selectOptions[focusedItemIndex] : null;
191	
192	    switch (event.key) {
193	      case 'Enter':
194	        if (isOpen && focusedItem && !focusedItem.isAriaDisabled) {
195	          onSelect(undefined, focusedItem.value as string);
196	        }
197	
198	        if (!isOpen) {
199	          setIsOpen(true);
200	        }
201	
202	        break;
203	      case 'ArrowUp':
204	      case 'ArrowDown':
205	        event.preventDefault();
206	        handleMenuArrowKeys(event.key);
207	        break;
208	    }
209	  };
210	
211	  const onToggleClick = () => {
212	    setIsOpen((open) => !open);
213	    textInputRef?.current?.focus();
214	  };
215	
216	  const onClearButtonClick = () => {
217	    setSelected('');
218	    setInputValue('');
219	    setFilterValue('');
220	    resetActiveAndFocusedItem();
221	    textInputRef?.current?.focus();
222	  };
223	
224	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
225	    <MenuToggle
226	      isExpanded={isOpen}
227	      isFullWidth={isFullWidth}
228	      onClick={onToggleClick}
229	      ref={toggleRef}
230	      variant="typeahead"
231	    >
232	      <TextInputGroup isPlain>
233	        <TextInputGroupMain
234	          autoComplete="off"
235	          icon={<SearchIcon />}
236	          innerRef={textInputRef}
237	          onChange={onTextInputChange}
238	          onClick={onToggleClick}
239	          onKeyDown={onInputKeyDown}
240	          placeholder={placeholder}
241	          value={inputValue}
242	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
243	          isExpanded={isOpen}
244	          role="combobox"
245	        />
246	
247	        {!isEmpty(inputValue) && (
248	          <TextInputGroupUtilities>
249	            <Button onClick={onClearButtonClick} variant={ButtonVariant.plain}>
250	              <TimesIcon />
251	            </Button>
252	          </TextInputGroupUtilities>
253	        )}
254	      </TextInputGroup>
255	    </MenuToggle>
256	  );
257	
258	  return (
259	    <Select
260	      onOpenChange={(open) => {
261	        !open && closeMenu();
262	      }}
263	      data-test={dataTestId}
264	      id={dataTestId}
265	      isOpen={isOpen}
266	      onSelect={onSelect}
267	      selected={selected}
268	      toggle={toggle}
269	    >
270	      <SelectList>
271	        {selectOptions?.map((option, index) => (
272	          <SelectOption
273	            className={option.className}
274	            id={createItemId(option.value)}
275	            isFocused={focusedItemIndex === index}
276	            key={option.value || option.children}
277	            {...option}
278	          />
279	        ))}
280	      </SelectList>
281	    </Select>
282	  );
283	};
284	
285	export default SelectTypeahead;

